// ─── QR Code canvas ───────────────────────────────────────────────────────────
function QRCanvas({ value }) {
  const ref=useRef(null)
  useEffect(()=>{
    if(!value||!ref.current) return
    const go=()=>window.QRCode.toCanvas(ref.current,value,{width:148,margin:2,color:{dark:"#0D1117",light:"#F4F6F8"}})
    if(window.QRCode){go();return}
    const s=document.createElement("script"); s.src="https://cdn.jsdelivr.net/npm/qrcode@1.5.3/build/qrcode.min.js"; s.onload=go; document.head.appendChild(s)
  },[value])
  return <canvas ref={ref} style={{ borderRadius:8,display:"block" }} />
}

// ─── QR Scanner ───────────────────────────────────────────────────────────────
function QRScanner({ onResult, label="📷 Scanner un QR Code" }) {
  const vRef=useRef(null),cRef=useRef(null),rafRef=useRef(null),stRef=useRef(null)
  const [active,setActive]=useState(false),[loading,setLoading]=useState(false),[error,setError]=useState(null)
  const loadJsQR=()=>new Promise((res,rej)=>{ if(window.jsQR)return res(window.jsQR); const s=document.createElement("script"); s.src="https://cdn.jsdelivr.net/npm/jsqr@1.4.0/dist/jsQR.js"; s.onload=()=>res(window.jsQR); s.onerror=()=>rej(); document.head.appendChild(s) })
  const stop=useCallback(()=>{ cancelAnimationFrame(rafRef.current); stRef.current?.getTracks().forEach(t=>t.stop()); stRef.current=null; setActive(false) },[])
  const start=useCallback(async()=>{
    setLoading(true); setError(null)
    try {
      const jsQR=await loadJsQR()

      // Essai 1 : caméra arrière (téléphone)
      let stream=null
      try {
        stream=await navigator.mediaDevices.getUserMedia({video:{facingMode:"environment",width:{ideal:640},height:{ideal:480}}})
      } catch(e1) {
        // Essai 2 : n'importe quelle caméra (ordinateur ou téléphone sans caméra arrière)
        try {
          stream=await navigator.mediaDevices.getUserMedia({video:true})
        } catch(e2) {
          throw e2
        }
      }

      stRef.current=stream
      setActive(true)
      setLoading(false)
      // Attendre que React monte le <video> dans le DOM
      await new Promise(r=>setTimeout(r,100))
      const v=vRef.current
      if(!v){ stop(); return }
      v.srcObject=stream
      await v.play()
      const tick=()=>{
        if(v.readyState!==v.HAVE_ENOUGH_DATA){rafRef.current=requestAnimationFrame(tick);return}
        const cv=cRef.current,ctx=cv.getContext("2d"); cv.width=v.videoWidth; cv.height=v.videoHeight; ctx.drawImage(v,0,0)
        const img=ctx.getImageData(0,0,cv.width,cv.height),res=jsQR(img.data,img.width,img.height,{inversionAttempts:"dontInvert"})
        if(res?.data){stop();bipScan(true);onResult(res.data);return}
        rafRef.current=requestAnimationFrame(tick)
      }
      rafRef.current=requestAnimationFrame(tick)
    } catch(e){
      setLoading(false)
      console.error("🎥 Erreur caméra :", e.name, e.message)
      if(e.name==="NotAllowedError"||e.name==="PermissionDeniedError")
        setError("Accès caméra refusé — autorisez la caméra dans les paramètres du navigateur")
      else if(e.name==="NotFoundError"||e.name==="DevicesNotFoundError")
        setError("Aucune caméra détectée sur cet appareil — utilisez la recherche manuelle")
      else if(e.name==="NotSupportedError")
        setError("Caméra non supportée sur ce navigateur — essayez Chrome ou Firefox")
      else
        setError(`Erreur caméra (${e.name}) — utilisez la recherche manuelle`)
    }
  },[onResult,stop])
  useEffect(()=>()=>stop(),[stop])
  return (
    <div>
      {!active&&!loading&&<button onClick={start} style={{ display:"flex",alignItems:"center",justifyContent:"center",gap:8,background:bg,color:accent,border:`1px solid ${accent}55`,borderRadius:8,padding:"10px 16px",width:"100%",fontSize:13,fontWeight:700,cursor:"pointer" }}>{label}</button>}
      {loading&&<div style={{ textAlign:"center",padding:"12px 0",color:sub,fontSize:13 }}>⏳ Démarrage caméra…</div>}
      {error&&<div style={{ background:red+"18",border:`1px solid ${red}44`,borderRadius:8,padding:"8px 14px",fontSize:12,color:red,marginTop:6 }}>⚠️ {error}</div>}
      {active&&(
        <div style={{ position:"relative",borderRadius:10,overflow:"hidden" }}>
          <video ref={vRef} style={{ width:"100%",display:"block",maxHeight:210,objectFit:"cover",background:"#000" }} muted playsInline />
          <div style={{ position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",width:130,height:130,pointerEvents:"none" }}>
            {[["top","left"],["top","right"],["bottom","left"],["bottom","right"]].map(([v,h])=>(
              <div key={v+h} style={{ position:"absolute",[v]:0,[h]:0,width:22,height:22,borderTop:v==="top"?`2px solid ${accent}`:"none",borderBottom:v==="bottom"?`2px solid ${accent}`:"none",borderLeft:h==="left"?`2px solid ${accent}`:"none",borderRight:h==="right"?`2px solid ${accent}`:"none" }} />
            ))}
          </div>
          <div style={{ position:"absolute",bottom:0,left:0,right:0,background:"rgba(0,0,0,0.65)",padding:"6px 12px",display:"flex",justifyContent:"space-between",alignItems:"center" }}>
            <span style={{ fontSize:12,color:accent }}>● Scan actif</span>
            <button style={{ background:red+"cc",color:"#fff",border:"none",borderRadius:5,padding:"3px 10px",fontSize:12,cursor:"pointer" }} onClick={stop}>Arrêter</button>
          </div>
        </div>
      )}
      <canvas ref={cRef} style={{ display:"none" }} />
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════════════════════
//  HOOK CENTRAL — Supabase via REST + polling toutes les 10s
// ═══════════════════════════════════════════════════════════════════════════════
function useForumData(notify) {
  const [P,setP]=useState([]),[S,setS]=useState([]),[V,setV]=useState([])
  const [loading,setLoading]=useState(true),[online,setOnline]=useState(false)

  const reload=useCallback(async()=>{
    try {
      const [rP,rS,rV]=await Promise.all([
        api.get("participants"),
        api.get("stands"),
        api.get("visites"),
      ])
      if(Array.isArray(rP)) setP(rP)
      if(Array.isArray(rS)) setS(rS)
      if(Array.isArray(rV)) setV(rV)
      setOnline(true)
    } catch(e){ setOnline(false) }
  },[])

  // Chargement initial
  useEffect(()=>{ reload().finally(()=>setLoading(false)) },[])

  // Polling toutes les 8 secondes (synchronisation multi-appareils)
  useEffect(()=>{ const t=setInterval(reload,8000); return ()=>clearInterval(t) },[reload])

  // ── Opérations ──
  const addParticipant=async(p)=>{
    const r=await api.post("participants",p)
    if(r?.code){ notify("❌ "+r.message,false); return false }
    await reload(); return true
  }
  const checkIn=async(id)=>{
    await api.patch("participants",`id=eq.${id}`,{statut:"PRESENT",heure:nowTime()})
    await reload(); return true
  }
  const addVisite=async(v)=>{
    const r=await api.post("visites",v)
    if(r?.code){ notify("❌ "+r.message,false); return false }
    await reload(); return true
  }
  const addStand=async(s)=>{
    const r=await api.post("stands",s)
    if(r?.code){ notify("❌ "+r.message,false); return false }
    await reload(); return true
  }
  const updateStand=async(id,data)=>{
    await api.patch("stands",`id=eq.${id}`,data)
    await reload(); return true
  }
  const removeStand=async(id)=>{
    await api.delete("stands",`id=eq.${id}`)
    await reload(); return true
  }
  const importBatch=async(list)=>{
    // Envoi par lots de 50
    const chunks=[]; for(let i=0;i<list.length;i+=50) chunks.push(list.slice(i,i+50))
    for(const chunk of chunks) await api.upsert("participants",chunk)
    await reload(); return list.length
  }

  return { P,S,V,loading,online,reload,addParticipant,checkIn,addVisite,addStand,updateStand,removeStand,importBatch }
}

